    // Enhanced hero animation effects matching AboutPage
    useEffect(() => {
        setIsHeroVisible(true);
        createTeamHeroAnimatedElements();
        
        const sections = document.querySelectorAll('.about-section');
        
        const observer = new IntersectionObserver((entries) => {
            entries.forEach(entry => {
                if (entry.isIntersecting) {
                    entry.target.classList.add('visible');
                }
            });
        }, { threshold: 0.1 });
        
        sections.forEach(section => {
            observer.observe(section);
        });
        
        return () => {
            sections.forEach(section => {
                observer.unobserve(section);
            });
            
            const elements = document.querySelector('.about-hero-elements');
            if (elements) {
                while (elements.firstChild) {
                    elements.removeChild(elements.firstChild);
                }
            }
        };
    }, []);

    // Team-specific animated elements
    const createTeamHeroAnimatedElements = () => {
        const container = document.querySelector('.about-hero-elements');
        if (!container) return;
        
        // Clear existing elements
        while (container.firstChild) {
            container.removeChild(container.firstChild);
        }
        
        // Create animated shapes with team theme
        for (let i = 0; i < 25; i++) {
            const shape = document.createElement('div');
            shape.className = 'about-shape';
            
            const shapes = ['circle', 'triangle', 'square', 'plus', 'hexagon'];
            const shapeType = shapes[Math.floor(Math.random() * shapes.length)];
            shape.classList.add(`shape-${shapeType}`);
            
            const x = Math.random() * 100;
            const y = Math.random() * 100;
            const size = Math.random() * 40 + 15;
            const opacity = Math.random() * 0.6 + 0.1;
            const animationDelay = Math.random() * 8;
            const animationDuration = Math.random() * 25 + 15;
            
            shape.style.left = `${x}%`;
            shape.style.top = `${y}%`;
            shape.style.width = `${size}px`;
            shape.style.height = `${size}px`;
            shape.style.opacity = opacity;
            shape.style.animationDelay = `${animationDelay}s`;
            shape.style.animationDuration = `${animationDuration}s`;
            
            container.appendChild(shape);
        }
        
        // Create floating team-related icons
        const teamIcons = ['people', 'groups', 'supervisor_account', 'psychology', 'school', 'emoji_people', 'group_work', 'diversity_1'];
        for (let i = 0; i < 8; i++) {
            const iconWrapper = document.createElement('div');
            iconWrapper.className = 'about-hero-icon team-hero-icon';
            
            const x = 5 + (Math.random() * 90);
            const y = 5 + (Math.random() * 90);
            const delay = Math.random() * 6;
            const scale = 0.8 + Math.random() * 0.4;
            
            iconWrapper.style.left = `${x}%`;
            iconWrapper.style.top = `${y}%`;
            iconWrapper.style.animationDelay = `${delay}s`;
            iconWrapper.style.transform = `scale(${scale})`;
            
            const icon = document.createElement('span');
            icon.className = 'material-icons';
            icon.textContent = teamIcons[i % teamIcons.length];
            
            iconWrapper.appendChild(icon);
            container.appendChild(iconWrapper);
        }
        
        // Add floating particles
        for (let i = 0; i < 15; i++) {
            const particle = document.createElement('div');
            particle.className = 'floating-particle';
            
            const x = Math.random() * 100;
            const y = Math.random() * 100;
            const size = Math.random() * 3 + 1;
            const duration = Math.random() * 20 + 10;
            const delay = Math.random() * 5;
            
            particle.style.left = `${x}%`;
            particle.style.top = `${y}%`;
            particle.style.width = `${size}px`;
            particle.style.height = `${size}px`;
            particle.style.animationDuration = `${duration}s`;
            particle.style.animationDelay = `${delay}s`;
            
            container.appendChild(particle);
        }
