            bio: 'David oversees all academic programs at Forum Academy and ensures the highest quality of education for our students. Under his leadership, the academy has achieved remarkable growth and recognition.',
            education: ['Ed.D. Educational Leadership - Harvard', 'M.B.A. - Wharton'],
            achievements: ['Excellence in Education Award', 'Led 300% Growth in Student Enrollment', 'Academic Innovation Leader'],
            social: {
                linkedin: 'https://linkedin.com/in/davidthompson'
            }
        },
        {
            id: 2,
            name: 'Lisa Park',
            title: 'Student Success Manager',
            department: 'Student Services',
            image: 'https://images.unsplash.com/photo-1489424731084-a5d8b219a5bb?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'lisa.park@forumacademy.edu',
            phone: '+1 (555) 567-8901',
            location: 'Seattle, WA',
            experience: '7 years',
            rating: 4.8,
            students: 1800,
            specializations: ['Student Support', 'Career Counseling', 'Academic Advising', 'Mentorship'],
            bio: 'Lisa is dedicated to ensuring every student achieves their academic and career goals through personalized support and guidance. Her mentorship has transformed countless student journeys.',
            education: ['M.S. Student Affairs - University of Washington', 'B.A. Psychology - UCLA'],
            achievements: ['Student Advocate of the Year', '95% Student Satisfaction Rate', 'Mentorship Excellence Award'],
            social: {
                linkedin: 'https://linkedin.com/in/lisapark'
            }
        },
        {
            id: 3,
            name: 'Robert Kim',
            title: 'Technology Operations Manager',
            department: 'IT Operations',
            image: 'https://images.unsplash.com/photo-1519085360753-af0119f7cbe7?ixlib=rb-4.0.3&auto=format&fit=crop&w=400&h=400&q=80',
            email: 'robert.kim@forumacademy.edu',
            phone: '+1 (555) 678-9012',
            location: 'Denver, CO',
            experience: '10 years',
            rating: 4.9,
            students: 0,
            specializations: ['Cloud Infrastructure', 'System Administration', 'EdTech Solutions', 'Network Security'],
            bio: 'Robert manages all technology infrastructure and ensures our learning platforms run smoothly for optimal student experience. His technical expertise keeps Forum Academy at the forefront of educational technology.',
            education: ['M.S. Information Systems - Colorado State', 'B.S. Computer Engineering - CU Boulder'],
            achievements: ['99.9% System Uptime', 'Cloud Migration Excellence Award', 'Tech Innovation Leader'],
            social: {
                linkedin: 'https://linkedin.com/in/robertkim',
                github: 'https://github.com/robertkim'
            }
        }
    ];

    const openModal = (member) => {
        setSelectedMember(member);
        document.body.style.overflow = 'hidden';
    };

    const closeModal = () => {
        setSelectedMember(null);
        document.body.style.overflow = 'unset';
    };

    const tabs = [
        { id: 'teachers', label: t('team.teachers') || 'Our Instructors', icon: GraduationCap, count: teachersData.length },
        { id: 'admin', label: t('team.administration') || 'Leadership Team', icon: Shield, count: adminData.length }
    ];

    // Enhanced Team Card Component
    const TeamCard = ({ member, type }) => (
        <div className="group relative">
            <div className="team-card-container relative w-full h-96 perspective-1000">
                <div className="team-card-inner relative w-full h-full transition-transform duration-700 transform-style-preserve-3d group-hover:rotate-y-180">
                    {/* Front Side */}
                    <div className="team-card-front absolute inset-0 w-full h-full backface-hidden">
                        <div className="relative w-full h-full bg-gradient-to-br from-white via-blue-50 to-purple-50 rounded-2xl shadow-lg border border-gray-200 overflow-hidden">
                            {/* Background Pattern */}
                            <div className="absolute inset-0 opacity-5">
                                <div className="absolute top-4 right-4 w-20 h-20 border-2 border-blue-300 rounded-full"></div>
                                <div className="absolute bottom-4 left-4 w-16 h-16 border-2 border-purple-300 rounded-full"></div>
                                <div className="absolute top-1/2 left-1/2 transform -translate-x-1/2 -translate-y-1/2 w-32 h-32 border border-gray-300 rounded-full"></div>
                            </div>
                            
                            {/* Department Badge */}
                            <div className="absolute top-4 left-4 z-10">
                                <div className="px-3 py-1 bg-gradient-to-r from-blue-500 to-purple-600 text-white text-xs font-semibold rounded-full shadow-lg">
                                    {member.department}
                                </div>
                            </div>
                            
                            {/* Rating Badge */}
                            {member.rating && (
                                <div className="absolute top-4 right-4 z-10">
                                    <div className="flex items-center space-x-1 px-2 py-1 bg-yellow-400 text-yellow-900 text-xs font-semibold rounded-full shadow-lg">
                                        <Star className="w-3 h-3 fill-current" />
                                        <span>{member.rating}</span>
                                    </div>
                                </div>
                            )}
                            
                            {/* Main Content */}
                            <div className="relative z-10 flex flex-col items-center justify-center h-full p-6">
                                <div className="relative mb-6">
                                    <div className="w-24 h-24 rounded-full overflow-hidden border-4 border-white shadow-xl">
                                        <img 
                                            src={member.image} 
                                            alt={member.name}
                                            className="w-full h-full object-cover"
                                        />
                                    </div>
                                    <div className="absolute -bottom-2 -right-2 w-8 h-8 bg-green-400 rounded-full border-4 border-white flex items-center justify-center">
                                        <div className="w-2 h-2 bg-white rounded-full"></div>
                                    </div>
                                </div>
                                
                                <h3 className="text-xl font-bold text-gray-900 text-center mb-2">{member.name}</h3>
                                <p className="text-sm font-medium text-blue-600 text-center mb-4">{member.title}</p>
                                
                                <div className="flex items-center space-x-4 text-sm text-gray-500 mb-4">
                                    <div className="flex items-center space-x-1">
                                        <MapPin className="w-4 h-4" />
                                        <span>{member.location}</span>
                                    </div>
                                    <div className="flex items-center space-x-1">
                                        <Clock className="w-4 h-4" />
                                        <span>{member.experience}</span>
                                    </div>
                                </div>
                                
                                {member.students > 0 && (
                                    <div className="text-center">
                                        <div className="text-2xl font-bold text-gray-900">{member.students}+</div>
                                        <div className="text-sm text-gray-500">Students Taught</div>
                                    </div>
                                )}
                            </div>
                            
                            {/* Hover Indicator */}
                            <div className="absolute bottom-4 left-1/2 transform -translate-x-1/2">
                                <div className="px-4 py-2 bg-gray-900/80 text-white text-xs rounded-full backdrop-blur-sm">
                                    Hover for details
                                </div>
                            </div>
                        </div>
                    </div>
                    
                    {/* Back Side */}
                    <div className="team-card-back absolute inset-0 w-full h-full backface-hidden rotate-y-180">
                        <div className="relative w-full h-full bg-gradient-to-br from-gray-900 via-blue-900 to-purple-900 rounded-2xl shadow-xl overflow-hidden">
                            {/* Background Pattern */}
                            <div className="absolute inset-0 opacity-10">
                                <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-br from-blue-400/20 to-purple-400/20"></div>
                                <div className="absolute top-4 right-4 w-20 h-20 border border-white/20 rounded-full"></div>
                                <div className="absolute bottom-4 left-4 w-16 h-16 border border-white/20 rounded-full"></div>
                            </div>
                            
                            <div className="relative z-10 p-6 h-full flex flex-col">
                                {/* Header */}
                                <div className="text-center mb-4">
                                    <h3 className="text-lg font-bold text-white mb-1">{member.name}</h3>
                                    <p className="text-blue-200 text-sm">{member.title}</p>
                                </div>
                                
                                {/* Specializations */}
                                <div className="mb-4">
                                    <div className="text-white text-xs font-semibold mb-2">Specializations:</div>
                                    <div className="flex flex-wrap gap-1">
                                        {member.specializations.slice(0, 4).map((spec, index) => (
                                            <span key={index} className="px-2 py-1 bg-white/20 text-white text-xs rounded-full">
                                                {spec}
                                            </span>
                                        ))}
                                        {member.specializations.length > 4 && (
                                            <span className="px-2 py-1 bg-white/20 text-white text-xs rounded-full">
                                                +{member.specializations.length - 4}
                                            </span>
                                        )}
                                    </div>
                                </div>
                                
                                {/* Bio */}
                                <div className="flex-1 mb-4">
                                    <p className="text-gray-200 text-xs leading-relaxed line-clamp-4">
                                        {member.bio}
                                    </p>
                                </div>
                                
                                {/* Contact & Social */}
                                <div className="space-y-3">
                                    <div className="flex items-center justify-between">
                                        <div className="flex space-x-2">
                                            {member.social?.linkedin && (
                                                <a href={member.social.linkedin} target="_blank" rel="noopener noreferrer" 
                                                   className="p-2 bg-white/20 rounded-lg hover:bg-white/30 transition-colors">
                                                    <Linkedin className="w-4 h-4 text-white" />
                                                </a>
                                            )}
                                            {member.social?.twitter && (
                                                <a href={member.social.twitter} target="_blank" rel="noopener noreferrer"
                                                   className="p-2 bg-white/20 rounded-lg hover:bg-white/30 transition-colors">
                                                    <Twitter className="w-4 h-4 text-white" />
                                                </a>
                                            )}
                                            {member.social?.github && (
                                                <a href={member.social.github} target="_blank" rel="noopener noreferrer"
                                                   className="p-2 bg-white/20 rounded-lg hover:bg-white/30 transition-colors">
                                                    <Github className="w-4 h-4 text-white" />
                                                </a>
                                            )}
                                            <a href={`mailto:${member.email}`} 
                                               className="p-2 bg-white/20 rounded-lg hover:bg-white/30 transition-colors">
                                                <Mail className="w-4 h-4 text-white" />
                                            </a>
                                        </div>
                                        
                                        <button
                                            onClick={() => openModal(member)}
                                            className="px-4 py-2 bg-white/20 hover:bg-white/30 text-white text-xs font-semibold rounded-lg transition-colors flex items-center space-x-1"
                                        >
                                            <span>View Profile</span>
                                            <ExternalLink className="w-3 h-3" />
                                        </button>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );

    return (
        <div className="about-page">
            <style jsx>{`
                .perspective-1000 {
                    perspective: 1000px;
                }
                
                .transform-style-preserve-3d {
                    transform-style: preserve-3d;
                }
                
                .backface-hidden {
                    backface-visibility: hidden;
                }
                
                .rotate-y-180 {
                    transform: rotateY(180deg);
                }
                
                .line-clamp-4 {
                    display: -webkit-box;
                    -webkit-line-clamp: 4;
                    -webkit-box-orient: vertical;
                    overflow: hidden;
                }
                
                .floating-particle {
                    position: absolute;
                    background: linear-gradient(45deg, #3b82f6, #8b5cf6);
                    border-radius: 50%;
                    animation: float 15s infinite ease-in-out;
                }
                
                @keyframes float {
                    0%, 100% { transform: translateY(0px) rotate(0deg); }
                    33% { transform: translateY(-20px) rotate(120deg); }
                    66% { transform: translateY(-10px) rotate(240deg); }
                }
                
                .team-hero-icon {
                    animation: teamFloat 12s infinite ease-in-out;
                }
                
                @keyframes teamFloat {
                    0%, 100% { transform: translateY(0px) scale(1) rotate(0deg); }
                    25% { transform: translateY(-15px) scale(1.1) rotate(90deg); }
                    50% { transform: translateY(-25px) scale(0.9) rotate(180deg); }
                    75% { transform: translateY(-10px) scale(1.05) rotate(270deg); }
                }
                
                .shape-hexagon {
                    clip-path: polygon(50% 0%, 100% 25%, 100% 75%, 50% 100%, 0% 75%, 0% 25%);
                }
            `}</style>

            {/* Enhanced Hero Section */}
            <section 
                ref={heroRef}
                className={`about-hero ${isHeroVisible ? 'visible' : ''}`}
            >
                <div className="about-hero-bg">
                    <div className="about-hero-elements"></div>
                    <div className="about-glow about-glow-1"></div>
                    <div className="about-glow about-glow-2"></div>
                </div>
                
                <div className="container">
                    <div className="about-hero-content">
                        <div className="about-hero-badge">
                            <span className="material-icons">people</span>
                            {t('team.hero.badge') || 'Meet Our Experts'}
                        </div>
                        
                        <h1 className="about-hero-title">
                            {t('team.hero.title') || 'Meet Our'} <span className="highlight-text">{t('team.hero.highlight') || 'Dream Team'}</span>
                        </h1>
                        
                        <p className="about-hero-description">
                            {t('team.hero.description') || 'Discover the passionate educators, industry experts, and visionary leaders who make Forum Academy a world-class institution for technology education and career transformation.'}
                        </p>
                        
                        <div className="about-hero-stats">
                            <div className="stat-item">
                                <div className="stat-number">50+</div>
                                <div className="stat-label">{t('team.stats.experts') || 'Expert Instructors'}</div>
                            </div>
                            <div className="stat-item">
                                <div className="stat-number">15+</div>
                                <div className="stat-label">{t('team.stats.experience') || 'Years Experience'}</div>
                            </div>
                            <div className="stat-item">
                                <div className="stat-number">4.9</div>
                                <div className="stat-label">{t('team.stats.rating') || 'Average Rating'}</div>
                            </div>
                            <div className="stat-item">
                                <div className="stat-number">5K+</div>
                                <div className="stat-label">{t('team.stats.students') || 'Students Mentored'}</div>
                            </div>
                        </div>
                        
                        <div className="about-hero-actions">
                            <a href="#team-members" className="btn btn-primary">{t('team.hero.meetTeam') || 'Meet Our Team'}</a>
                            <a href="/contact" className="btn btn-outline">{t('team.hero.joinUs') || 'Join Our Team'}</a>
                        </div>
                    </div>
                </div>
                
                <div className="scroll-indicator">
                    <a href="#team-members">
                        <span>{t('team.hero.exploreTeam') || 'Explore Our Team'}</span>
                        <span className="material-icons">keyboard_arrow_down</span>
                    </a>
                </div>
            </section>

            {/* Team Section */}
            <section id="team-members" className="about-section py-20">
                <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
                    {/* Section Header */}
                    <div className="text-center mb-16">
                        <h2 className="text-4xl font-bold text-gray-900 mb-4">
                            Our <span className="text-transparent bg-clip-text bg-gradient-to-r from-blue-600 to-purple-600">Professional Team</span>
                        </h2>
                        <p className="text-xl text-gray-600 max-w-3xl mx-auto">
                            Meet the dedicated professionals who bring years of industry experience and academic excellence to guide your learning journey.
                        </p>
                    </div>

                    {/* Enhanced Tab Navigation */}
                    <div className="flex justify-center mb-12">
                        <div className="bg-white rounded-2xl p-2 shadow-xl border border-gray-200/50 backdrop-blur-sm">
                            <div className="flex space-x-2">
                                {tabs.map((tab) => {
                                    const IconComponent = tab.icon;
                                    return (
                                        <button
                                            key={tab.id}
                                            onClick={() => setActiveTab(tab.id)}
                                            className={`relative flex items-center space-x-3 px-8 py-4 rounded-xl font-semibold transition-all duration-500 transform ${
                                                activeTab === tab.id
                                                    ? 'bg-gradient-to-r from-blue-500 to-purple-600 text-white shadow-lg scale-105'
                                                    : 'text-gray-600 hover:text-gray-900 hover:bg-gray-50 hover:scale-102'
                                            }`}
                                        >
                                            <IconComponent className="w-5 h-5" />
                                            <span>{tab.label}</span>
                                            <div className={`ml-2 px-2 py-1 rounded-full text-xs font-bold ${
                                                activeTab === tab.id 
                                                    ? 'bg-white/20 text-white' 
                                                    : 'bg-gray-200 text-gray-600'
                                            }`}>
                                                {tab.count}
                                            </div>
                                            {activeTab === tab.id && (
                                                <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-blue-500/20 to-purple-600/20 animate-pulse"></div>
                                            )}
                                        </button>
                                    );
                                })}
                            </div>
                        </div>
                    </div>

                    {/* Team Grid with Staggered Animation */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-2 xl:grid-cols-3 gap-8">
                        {(activeTab === 'teachers' ? teachersData : adminData).map((member, index) => (
                            <div 
                                key={member.id} 
                                className="transform transition-all duration-500 hover:scale-105"
                                style={{ 
                                    animationDelay: `${index * 100}ms`,
                                    animation: 'fadeInUp 0.6s ease-out forwards'
                                }}
                            >
                                <TeamCard member={member} type={activeTab} />
                            </div>
                        ))}
                    </div>

                    {/* Call to Action */}
                    <div className="text-center mt-16">
                        <div className="bg-gradient-to-r from-blue-50 to-purple-50 rounded-2xl p-8 border border-gray-200/50">
                            <h3 className="text-2xl font-bold text-gray-900 mb-4">Ready to Learn from the Best?</h3>
                            <p className="text-gray-600 mb-6 max-w-2xl mx-auto">
                                Join thousands of students who have transformed their careers with guidance from our expert instructors.
                            </p>
                            <div className="flex flex-col sm:flex-row gap-4 justify-center">
                                <a href="/courses" className="btn btn-primary">
                                    Explore Our Courses
                                </a>
                                <a href="/contact" className="btn btn-outline">
                                    Schedule a Consultation
                                </a>
                            </div>
                        </div>
                    </div>
                </div>
            </section>

            {/* Enhanced Team Modal */}
            {selectedMember && (
                <div className="fixed inset-0 bg-black/60 backdrop-blur-lg z-50 flex items-center justify-center p-4 animate-fadeIn">
                    <div className="bg-white rounded-3xl max-w-5xl w-full max-h-[90vh] overflow-y-auto shadow-2xl animate-slideUp">
                        <div className="relative">
                            {/* Header with gradient background */}
                            <div className="h-80 bg-gradient-to-br from-blue-600 via-purple-600 to-indigo-800 relative overflow-hidden">
                                {/* Background pattern */}
                                <div className="absolute inset-0 opacity-10">
                                    <div className="absolute top-10 left-10 w-32 h-32 border-2 border-white rounded-full"></div>
                                    <div className="absolute bottom-10 right-10 w-24 h-24 border-2 border-white rounded-full"></div>
                                    <div className="absolute top-1/2 right-1/4 w-16 h-16 border border-white rounded-full"></div>
                                </div>
                                
                                <div className="absolute inset-0 bg-gradient-to-t from-black/20 to-transparent"></div>
                                
                                <button
                                    onClick={closeModal}
                                    className="absolute top-6 right-6 p-3 bg-white/20 backdrop-blur-sm rounded-full hover:bg-white/30 transition-all duration-300 text-white group"
                                >
                                    <X className="w-6 h-6 group-hover:rotate-90 transition-transform duration-300" />
                                </button>
                                
                                <div className="absolute bottom-8 left-8 right-8">
                                    <div className="flex items-end space-x-8">
                                        <div className="relative">
                                            <img
                                                src={selectedMember.image}
                                                alt={selectedMember.name}
                                                className="w-32 h-32 rounded-3xl border-4 border-white shadow-2xl object-cover"
                                            />
                                            <div className="absolute -bottom-2 -right-2 w-10 h-10 bg-green-400 rounded-full border-4 border-white flex items-center justify-center">
                                                <div className="w-3 h-3 bg-white rounded-full"></div>
                                            </div>
                                        </div>
                                        <div className="text-white flex-1">
                                            <h2 className="text-4xl font-bold mb-2">{selectedMember.name}</h2>
                                            <p className="text-blue-100 text-xl font-medium mb-2">{selectedMember.title}</p>
                                            <div className="flex items-center space-x-6 text-blue-200">
                                                <div className="flex items-center space-x-2">
                                                    <Building className="w-5 h-5" />
                                                    <span>{selectedMember.department}</span>
                                                </div>
                                                <div className="flex items-center space-x-2">
                                                    <MapPin className="w-5 h-5" />
                                                    <span>{selectedMember.location}</span>
                                                </div>
                                                {selectedMember.rating && (
                                                    <div className="flex items-center space-x-2">
                                                        <Star className="w-5 h-5 fill-current text-yellow-400" />
                                                        <span>{selectedMember.rating}/5.0</span>
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div className="p-10">
                                <div className="grid grid-cols-1 lg:grid-cols-3 gap-10">
                                    {/* Main Content */}
                                    <div className="lg:col-span-2 space-y-8">
                                        <div>
                                            <h3 className="text-2xl font-bold text-gray-900 mb-4 flex items-center">
                                                <User className="w-6 h-6 mr-3 text-blue-600" />
                                                About {selectedMember.name.split(' ')[0]}
                                            </h3>
                                            <p className="text-gray-600 leading-relaxed text-lg">{selectedMember.bio}</p>
                                        </div>

                                        <div>
                                            <h3 className="text-2xl font-bold text-gray-900 mb-4 flex items-center">
                                                <BookOpen className="w-6 h-6 mr-3 text-blue-600" />
                                                Areas of Expertise
                                            </h3>
                                            <div className="grid grid-cols-2 gap-3">
                                                {selectedMember.specializations.map((spec, index) => (
                                                    <div key={index} className="flex items-center space-x-3 p-3 bg-gradient-to-r from-blue-50 to-purple-50 rounded-xl border border-blue-100">
                                                        <div className="w-2 h-2 bg-blue-500 rounded-full"></div>
                                                        <span className="text-gray-700 font-medium">{spec}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>

                                        <div>
                                            <h3 className="text-2xl font-bold text-gray-900 mb-4 flex items-center">
                                                <GraduationCap className="w-6 h-6 mr-3 text-blue-600" />
                                                Educational Background
                                            </h3>
                                            <div className="space-y-4">
                                                {selectedMember.education.map((edu, index) => (
                                                    <div key={index} className="flex items-start space-x-4 p-4 bg-gray-50 rounded-xl">
                                                        <div className="w-3 h-3 bg-blue-600 rounded-full mt-2 flex-shrink-0"></div>
                                                        <span className="text-gray-700 font-medium text-lg">{edu}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>

                                        <div>
                                            <h3 className="text-2xl font-bold text-gray-900 mb-4 flex items-center">
                                                <Award className="w-6 h-6 mr-3 text-blue-600" />
                                                Achievements & Recognition
                                            </h3>
                                            <div className="space-y-4">
                                                {selectedMember.achievements.map((achievement, index) => (
                                                    <div key={index} className="flex items-start space-x-4 p-4 bg-yellow-50 rounded-xl border border-yellow-200">
                                                        <Star className="w-5 h-5 text-yellow-500 mt-0.5 flex-shrink-0" />
                                                        <span className="text-gray-700 font-medium text-lg">{achievement}</span>
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    </div>

                                    {/* Enhanced Sidebar */}
                                    <div className="space-y-8">
                                        {/* Quick Stats */}
                                        <div className="bg-gradient-to-br from-blue-50 to-purple-50 rounded-2xl p-6 border border-blue-100">
                                            <h3 className="font-bold text-gray-900 mb-6 text-xl">Quick Stats</h3>
                                            <div className="space-y-4">
                                                <div className="flex items-center justify-between">
                                                    <span className="text-gray-600">Experience</span>
                                                    <span className="font-bold text-blue-600">{selectedMember.experience}</span>
                                                </div>
                                                {selectedMember.students > 0 && (
                                                    <div className="flex items-center justify-between">
                                                        <span className="text-gray-600">Students Taught</span>
                                                        <span className="font-bold text-purple-600">{selectedMember.students}+</span>
                                                    </div>
                                                )}
                                                {selectedMember.rating && (
                                                    <div className="flex items-center justify-between">
                                                        <span className="text-gray-600">Rating</span>
                                                        <div className="flex items-center space-x-1">
                                                            <Star className="w-4 h-4 text-yellow-500 fill-current" />
                                                            <span className="font-bold text-yellow-600">{selectedMember.rating}/5.0</span>
                                                        </div>
                                                    </div>
                                                )}
                                                <div className="flex items-center justify-between">
                                                    <span className="text-gray-600">Specializations</span>
                                                    <span className="font-bold text-green-600">{selectedMember.specializations.length}</span>
                                                </div>
                                            </div>
                                        </div>

                                        {/* Contact Information */}
                                        <div className="bg-gray-50 rounded-2xl p-6">
                                            <h3 className="font-bold text-gray-900 mb-6 text-xl">Contact Information</h3>
                                            <div className="space-y-4">
                                                <div className="flex items-center space-x-3">
                                                    <div className="p-2 bg-blue-100 rounded-lg">
                                                        <Mail className="w-5 h-5 text-blue-600" />
                                                    </div>
                                                    <div className="flex-1">
                                                        <div className="text-sm text-gray-500">Email</div>
                                                        <a href={`mailto:${selectedMember.email}`} className="text-blue-600 hover:text-blue-700 font-medium">
                                                            {selectedMember.email}
                                                        </a>
                                                    </div>
                                                </div>
                                                <div className="flex items-center space-x-3">
                                                    <div className="p-2 bg-green-100 rounded-lg">
                                                        <Phone className="w-5 h-5 text-green-600" />
                                                    </div>
                                                    <div className="flex-1">
                                                        <div className="text-sm text-gray-500">Phone</div>
                                                        <span className="text-gray-700 font-medium">{selectedMember.phone}</span>
                                                    </div>
                                                </div>
                                                <div className="flex items-center space-x-3">
                                                    <div className="p-2 bg-purple-100 rounded-lg">
                                                        <MapPin className="w-5 h-5 text-purple-600" />
                                                    </div>
                                                    <div className="flex-1">
                                                        <div className="text-sm text-gray-500">Location</div>
                                                        <span className="text-gray-700 font-medium">{selectedMember.location}</span>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>

                                        {/* Social Links */}
                                        {selectedMember.social && (
                                            <div className="bg-gray-50 rounded-2xl p-6">
                                                <h3 className="font-bold text-gray-900 mb-6 text-xl">Connect & Follow</h3>
                                                <div className="grid grid-cols-2 gap-3">
                                                    {selectedMember.social.linkedin && (
                                                        <a 
                                                            href={selectedMember.social.linkedin} 
                                                            target="_blank" 
                                                            rel="noopener noreferrer"
                                                            className="flex items-center justify-center p-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 transition-all duration-300 transform hover:scale-105"
                                                        >
                                                            <Linkedin className="w-5 h-5" />
                                                        </a>
                                                    )}
                                                    {selectedMember.social.twitter && (
                                                        <a 
                                                            href={selectedMember.social.twitter} 
                                                            target="_blank" 
                                                            rel="noopener noreferrer"
                                                            className="flex items-center justify-center p-3 bg-blue-400 text-white rounded-xl hover:bg-blue-500 transition-all duration-300 transform hover:scale-105"
                                                        >
                                                            <Twitter className="w-5 h-5" />
                                                        </a>
                                                    )}
                                                    {selectedMember.social.github && (
                                                        <a 
                                                            href={selectedMember.social.github} 
                                                            target="_blank" 
                                                            rel="noopener noreferrer"
                                                            className="flex items-center justify-center p-3 bg-gray-800 text-white rounded-xl hover:bg-gray-900 transition-all duration-300 transform hover:scale-105"
                                                        >
                                                            <Github className="w-5 h-5" />
                                                        </a>
                                                    )}
                                                    <a 
                                                        href={`mailto:${selectedMember.email}`}
                                                        className="flex items-center justify-center p-3 bg-green-600 text-white rounded-xl hover:bg-green-700 transition-all duration-300 transform hover:scale-105"
                                                    >
                                                        <Mail className="w-5 h-5" />
                                                    </a>
                                                </div>
                                            </div>
                                        )}

                                        {/* Call to Action */}
                                        <div className="bg-gradient-to-r from-blue-600 to-purple-600 rounded-2xl p-6 text-white">
                                            <h3 className="font-bold mb-2 text-xl">Interested in Learning?</h3>
                                            <p className="text-blue-100 mb-4 text-sm">
                                                Get in touch to learn more about courses and programs.
                                            </p>
                                            <a 
                                                href="/contact" 
                                                className="block text-center bg-white text-blue-600 font-semibold py-3 px-6 rounded-xl hover:bg-blue-50 transition-colors duration-300"
                                            >
                                                Get Started Today
                                            </a>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}

            <style jsx>{`
                @keyframes fadeInUp {
                    from {
                        opacity: 0;
                        transform: translateY(30px);
                    }
                    to {
                        opacity: 1;
                        transform: translateY(0);
                    }
                }
                
                @keyframes fadeIn {
                    from { opacity: 0; }
                    to { opacity: 1; }
                }
                
                @keyframes slideUp {
                    from {
                        opacity: 0;
                        transform: translateY(50px) scale(0.95);
                    }
                    to {
                        opacity: 1;
                        transform: translateY(0) scale(1);
                    }
                }
                
                .animate-fadeIn {
                    animation: fadeIn 0.3s ease-out;
                }
                
                .animate-slideUp {
                    animation: slideUp 0.4s ease-out;
                }
                
                .hover\\:scale-102:hover {
                    transform: scale(1.02);
                }
            `}</style>
        </div>
    );
};

export default Team;
